from src.strategies.implemented_strategies import BaseImplementedStrategy
import pandas as pd
import numpy as np

class GeneratedStrategyTemplate(BaseImplementedStrategy):
    def __init__(self):
        super().__init__("26", "多周期序列驱动策略", trigger_timeframe="15min")
        self.history = {}
        self.last_buy_day = {}
        self.entry_price = {}
        self.stop_loss_price = {}
        self.sequence_count = {}
        self.pending_sell = set()

    def on_bar(self, kline):
        code = kline['code']
        close = float(kline.get('close', 0))
        high = float(kline.get('high', 0))
        low = float(kline.get('low', 0))
        volume = float(kline.get('volume', 0))
        dt = kline['dt']
        curr_day = pd.to_datetime(dt).strftime('%Y-%m-%d')

        # === 基础数据过滤 ===
        if volume <= 0 or close <= 0 or high < low:
            return None

        # === 初始化历史数据 ===
        if code not in self.history:
            self.history[code] = pd.DataFrame()
        self.history[code] = pd.concat([self.history[code], pd.DataFrame([kline])], ignore_index=True).tail(200)
        df = self.history[code]
        if len(df) < 30:
            return None

        close_series = pd.to_numeric(df['close'], errors='coerce').dropna()
        if len(close_series) < 30:
            return None

        # === T+1限制：当日买入不得卖出 ===
        if code in self.last_buy_day and self.last_buy_day[code] == curr_day:
            if code in self.pending_sell:
                self.pending_sell.discard(code)
            return None

        # === 涨跌停限制 ===
        if 'limit_up' in kline and kline['limit_up']:
            # 接近涨停禁止追高买入
            if code not in self.positions or self.positions[code] <= 0:
                return None
        if 'limit_down' in kline and kline['limit_down']:
            # 跌停或接近跌停不得卖出，次日重试
            if code in self.positions and self.positions[code] > 0:
                self.pending_sell.add(code)
            return None

        # === pending_sell重试机制 ===
        if code in self.pending_sell:
            self.pending_sell.discard(code)
            qty = int(self.positions.get(code, 0))
            if qty > 0:
                return self.create_exit_signal(kline, qty, "跌停重试卖出")

        # === 计算6K序列 ===
        def calculate_sequence(series):
            count = 0
            for i in range(len(series)-1, -1, -1):
                if i < 4:
                    break
                if series.iloc[i] > series.iloc[i - 4]:
                    count += 1
                else:
                    break
            return count

        sequence_len = calculate_sequence(close_series)

        qty = int(self.positions.get(code, 0))
        buy_qty = int(self._qty())

        # === 交易单位控制 ===
        if buy_qty % 100 != 0:
            buy_qty = (buy_qty // 100) * 100
        if buy_qty < 100:
            buy_qty = 0

        # === 入场条件 ===
        if qty <= 0 and sequence_len >= 6 and buy_qty > 0:
            # 禁止重复开仓
            self.last_buy_day[code] = curr_day
            entry_price = close
            self.entry_price[code] = entry_price
            hard_stop = entry_price * 0.99

            # 动态止损：最近3K最低价
            if len(close_series) >= 3:
                dynamic_stop = float(close_series.iloc[-3:].min())
            else:
                dynamic_stop = hard_stop
            stop_loss = max(hard_stop, dynamic_stop)
            self.stop_loss_price[code] = stop_loss

            return {
                'strategy_id': self.id,
                'code': code,
                'dt': dt,
                'direction': 'BUY',
                'price': close,
                'qty': buy_qty,
                'stop_loss': stop_loss,
                'take_profit': None
            }

        # === 出场条件（风控优先） ===
        if qty > 0:
            entry_price = self.entry_price.get(code, close)
            stop_loss = self.stop_loss_price.get(code, entry_price * 0.99)

            # 止损优先
            if close < stop_loss:
                return self.create_exit_signal(kline, qty, "止损触发")

            # 序列失效
            if len(close_series) >= 5 and close_series.iloc[-1] <= close_series.iloc[-5]:
                return self.create_exit_signal(kline, qty, "序列失效")

            # 趋势耗尽
            if sequence_len >= 23:
                return self.create_exit_signal(kline, qty, "趋势耗尽")

        return None

from src.strategies.implemented_strategies import BaseImplementedStrategy
import pandas as pd

class Sequence6Strategy(BaseImplementedStrategy):
    def __init__(self):
        super().__init__("S08_SEQ6", "6K序列趋势策略", trigger_timeframe="15min")
        self.history = {}
        self.entry_price = {}

    def on_bar(self, kline):
        code = kline['code']

        # === 数据缓存 ===
        if code not in self.history:
            self.history[code] = pd.DataFrame()

        self.history[code] = pd.concat(
            [self.history[code], pd.DataFrame([kline])],
            ignore_index=True
        ).tail(1000)

        df = self.history[code]

        # === 数据不足直接返回 ===
        if len(df) < 30:
            return None

        df['close'] = pd.to_numeric(df['close'], errors='coerce')
        df['low'] = pd.to_numeric(df['low'], errors='coerce')

        close = df['close']
        low = df['low']

        # === 当前持仓 ===
        qty = int(self.positions.get(code, 0))
        price = float(kline['close'])

        # === 计算6K序列 ===
        seq = 0
        for i in range(len(close) - 1, 4, -1):
            if close.iloc[i] > close.iloc[i - 4]:
                seq += 1
            else:
                break

        # === 入场逻辑（多头） ===
        if qty == 0:
            if seq >= 6:
                buy_qty = int(self._qty())
                if buy_qty <= 0:
                    return None

                # A股100股约束
                buy_qty = (buy_qty // 100) * 100
                if buy_qty < 100:
                    return None

                self.entry_price[code] = price

                # 止损：严格≤1%
                stop_loss = price * 0.99

                return {
                    'strategy_id': self.id,
                    'code': code,
                    'dt': kline['dt'],
                    'direction': 'BUY',
                    'price': price,
                    'qty': buy_qty,
                    'stop_loss': stop_loss,
                    'take_profit': None
                }

        # === 持仓逻辑 ===
        if qty > 0:

            # --- 动态止损（最近3K最低） ---
            if len(low) >= 3:
                stop_dynamic = low.iloc[-3:].min()
            else:
                stop_dynamic = price * 0.99

            # --- 硬止损 ---
            if price <= self.entry_price.get(code, price) * 0.99:
                return self.create_exit_signal(kline, qty, "Hard StopLoss")

            # --- 动态止损触发 ---
            if price < stop_dynamic:
                return self.create_exit_signal(kline, qty, "Dynamic StopLoss")

            # --- 序列失效 ---
            if close.iloc[-1] <= close.iloc[-5]:
                return self.create_exit_signal(kline, qty, "Sequence Break")

            # --- 超过23K强制退出 ---
            if seq >= 23:
                return self.create_exit_signal(kline, qty, "Max Sequence Exit")

        return None

