        ema_short = Indicators.EMA(close_series, 10)
        ema_long = Indicators.EMA(close_series, 20)
        if len(ema_short) < 5 or len(ema_long) < 5:
            return None

        qty = int(self.positions.get(code, 0))
        self.update_holding_time(code)

        try:
            es_1 = float(ema_short.iloc[-1])
            es_2 = float(ema_short.iloc[-2])
            es_3 = float(ema_short.iloc[-3])
            el_1 = float(ema_long.iloc[-1])
            el_2 = float(ema_long.iloc[-2])
            el_3 = float(ema_long.iloc[-3])
        except Exception:
            return None

        trend_up = close > es_1 and close > el_1 and es_1 > el_1 and es_1 > es_2 > es_3 and el_1 > el_2 > el_3

        vol_ma20 = float(vol_series.iloc[-21:-1].mean())
        breakout_high = float(high_series.iloc[-41:-1].max())
        breakout_low = float(low_series.iloc[-41:-1].min())
        prev_close_value = float(close_series.iloc[-2])

        if qty > 0 and self.last_buy_day.get(code) == curr_day:
            return None

        if self.pending_sell.get(code, False):
            if qty > 0:
                self.pending_sell[code] = False
                self.trailing_stop_level.pop(code, None)
                self.highest_high.pop(code, None)
                self.last_sell_day[code] = curr_day
                return self.create_exit_signal(kline, qty, "Pending Sell Retry")
            self.pending_sell[code] = False

        if qty > 0:
            if close > self.highest_high.get(code, close):
                self.highest_high[code] = close

            recent_swing_low = float(low_series.iloc[-8:].min())
            dynamic_sl = max(el_1, recent_swing_low)
            old_sl = float(self.trailing_stop_level.get(code, dynamic_sl))
            new_sl = max(old_sl, dynamic_sl)
            self.trailing_stop_level[code] = new_sl

            if self.check_max_holding_time(code, 240):
                self.trailing_stop_level.pop(code, None)
                self.highest_high.pop(code, None)
                self.last_sell_day[code] = curr_day
                return self.create_exit_signal(kline, qty, "Time Exit")

            if close <= new_sl:
                self.trailing_stop_level.pop(code, None)
                self.highest_high.pop(code, None)
                self.last_sell_day[code] = curr_day
                return self.create_exit_signal(kline, qty, "Trailing Stop Exit")

            if close < el_1 and prev_close_value < float(ema_long.iloc[-2]):
                self.trailing_stop_level.pop(code, None)
                self.highest_high.pop(code, None)
                self.last_sell_day[code] = curr_day
                return self.create_exit_signal(kline, qty, "EMA Long Exit")

        same_day_reentry_block = self.last_sell_day.get(code) == curr_day
        volume_confirm = volume > vol_ma20 * 1.10 if vol_ma20 > 0 else False
        breakout_confirm = prev_close_value > breakout_high * 0.999 and close > breakout_high * 1.001
        extension_ok = close <= breakout_high * 1.03

        if qty <= 0 and trend_up and (not same_day_reentry_block):
            if volume_confirm and breakout_confirm and extension_ok:
                init_sl = min(breakout_low, el_1)
                stop_risk = close - init_sl
                if stop_risk <= 0:
                    return None

                total_value = float(getattr(self, 'total_value', 0.0) or 0.0)
                available_cash = float(getattr(self, 'available_cash', 0.0) or getattr(self, 'current_cash', 0.0) or 0.0)
                if total_value <= 0:
                    total_value = available_cash
                if available_cash <= 0 or total_value <= 0:
                    return None

                risk_budget = total_value * 0.018
                qty_by_risk = int(risk_budget // stop_risk)
                qty_by_cash = int((available_cash * 0.85) // close)
                raw_qty = min(qty_by_risk, qty_by_cash)
                buy_qty = (raw_qty // 100) * 100
                if buy_qty < 100:
                    return None

                self.last_buy_day[code] = curr_day
                self.entry_price[code] = close
                self.trailing_stop_level[code] = init_sl
                self.highest_high[code] = close
                return {
                    'strategy_id': self.id,
                    'code': code,
                    'dt': kline['dt'],
                    'direction': 'BUY',
                    'price': close,
                    'qty': buy_qty,
                    'stop_loss': init_sl,
                    'take_profit': None
                }

        return None
